def validate_redirect_uri(tenant_id, redirect_uri):
    """
    Securely validate that the redirect_uri exactly matches one of the
    pre-configured allowed redirect URIs for the tenant.

    SECURITY NOTE: We use exact string matching against an allowlist of
    pre-registered redirect URIs. This prevents open redirect attacks.

    Previously, a pattern like 'if domain in redirect_uri' was used, which
    is insecure because:
      - "example.com" in "https://evil-example.com/callback" => True
      - "example.com" in "https://attacker.com/?q=example.com" => True
      - An attacker can craft a URI containing the domain string anywhere
        (in path, query params, fragment, or as a substring of another domain)
        to bypass the check and redirect tokens to their server.

    The secure approach is to validate against an explicit allowlist of
    fully-qualified redirect URIs using exact match comparison.
    """
    tenant_config = TENANT_CONFIGS.get(tenant_id)
    if not tenant_config:
        return False

    allowed_uris = tenant_config.get("allowed_redirect_uris", [])

    # Exact match against the allowlist - no substring or pattern matching
    if redirect_uri not in allowed_uris:
        return False

    # Additional defense-in-depth: ensure the URI uses HTTPS
    parsed = urlparse(redirect_uri)
    if parsed.scheme != "https":
        return False

    return True


