    redirect_uri = session.get('oauth_redirect_uri')
    code_verifier = session.get('oauth_code_verifier')

    # Exchange authorization code for tokens
    import requests as http_requests
    token_response = http_requests.post(
        tenant_config['token_endpoint'],
        data={
            'grant_type': 'authorization_code',
            'code': code,
            'redirect_uri': redirect_uri,
            'client_id': tenant_config['client_id'],
            'client_secret': tenant_config['client_secret'],
            'code_verifier': code_verifier,
        },
        headers={'Accept': 'application/json'},
        timeout=10,
    )

    # Clean up session state
    session.pop('oauth_state', None)
    session.pop('oauth_tenant_id', None)
    session.pop('oauth_redirect_uri', None)
    session.pop('oauth_code_verifier', None)

    if token_response.status_code != 200:
        app.logger.error(f"Token exchange failed: {token_response.status_code}")
        return jsonify({'error': 'Token exchange failed'}), 500

    token_data = token_response.json()

    # Store tokens securely in session (in production, use encrypted storage)
